#include <iostream>
#include <functional>
#include <vector>
#include <string>

// --- Regular functions ---
int add(int a, int b) {
    return a + b;
}

int subtract(int a, int b) {
    return a - b;
}

int multiply(int a, int b) {
    return a * b;
}

void printMessage(const std::string& msg) {
    std::cout << msg << std::endl;
}

// --- Function that takes a function pointer ---
int applyOperation(int a, int b, int (*func)(int, int)) {
    return func(a, b);
}

// --- Function that takes std::function ---
int applyWithFunction(int a, int b, std::function<int(int, int)> func) {
    return func(a, b);
}

// --- Game example: Attack strategies ---
class Enemy {
public:
    std::string name;
    int health;

    Enemy(std::string n, int h) : name(n), health(h) {}
};

using AttackStrategy = std::function<void(Enemy&)>;

void normalAttack(Enemy& enemy) {
    enemy.health -= 10;
    std::cout << "🔨 Normal attack! " << enemy.name << " HP: " << enemy.health << std::endl;
}

void strongAttack(Enemy& enemy) {
    enemy.health -= 25;
    std::cout << "💥 Strong attack! " << enemy.name << " HP: " << enemy.health << std::endl;
}

void poisonAttack(Enemy& enemy) {
    enemy.health -= 5;
    std::cout << "☠️ Poison attack! " << enemy.name << " HP: " << enemy.health << std::endl;
}

// --- Class with member function ---
class Calculator {
public:
    int multiplyByTwo(int x) {
        return x * 2;
    }
};

int main() {
    std::cout << "=== Function Pointers & std::function ===" << std::endl;

    // 1. Function pointers
    std::cout << "\n--- Function Pointers ---" << std::endl;
    int (*funcPtr)(int, int) = add;
    std::cout << "add(5,3) = " << funcPtr(5, 3) << std::endl;

    funcPtr = multiply;
    std::cout << "multiply(5,3) = " << funcPtr(5, 3) << std::endl;

    // 2. Passing function pointer as parameter
    std::cout << "\n--- Passing Function Pointer ---" << std::endl;
    std::cout << "applyOperation(add, 10, 5) = " << applyOperation(10, 5, add) << std::endl;
    std::cout << "applyOperation(subtract, 10, 5) = " << applyOperation(10, 5, subtract) << std::endl;
    std::cout << "applyOperation(multiply, 10, 5) = " << applyOperation(10, 5, multiply) << std::endl;

    // 3. std::function
    std::cout << "\n--- std::function ---" << std::endl;
    std::function<int(int, int)> func = add;
    std::cout << "func(5,3) = " << func(5, 3) << std::endl;

    func = multiply;
    std::cout << "func(5,3) = " << func(5, 3) << std::endl;

    // 4. std::function with lambda
    std::cout << "\n--- std::function with Lambda ---" << std::endl;
    std::function<int(int, int)> lambdaFunc = [](int a, int b) {
        return a * a + b * b;
    };
    std::cout << "lambda(3,4) = " << lambdaFunc(3, 4) << std::endl;

    // 5. std::function with class method
    std::cout << "\n--- std::function with Class Method ---" << std::endl;
    Calculator calc;
    std::function<int(Calculator&, int)> methodFunc = &Calculator::multiplyByTwo;
    std::cout << "calc.multiplyByTwo(5) = " << methodFunc(calc, 5) << std::endl;

    // 6. Game use: Attack strategies
    std::cout << "\n--- Game: Attack Strategies ---" << std::endl;
    Enemy goblin("Goblin", 50);

    std::vector<AttackStrategy> strategies = {normalAttack, strongAttack, poisonAttack};

    std::cout << "Enemy HP: " << goblin.health << std::endl;
    for (const auto& strategy : strategies) {
        strategy(goblin);
    }

    std::cout << "Final HP: " << goblin.health << std::endl;

    // 7. Function pointer array
    std::cout << "\n--- Function Pointer Array ---" << std::endl;
    int (*operations[])(int, int) = {add, subtract, multiply};
    std::string names[] = {"add", "subtract", "multiply"};

    for (int i = 0; i < 3; i++) {
        std::cout << names[i] << "(10,5) = " << operations[i](10, 5) << std::endl;
    }

    std::cout << "\n--- Function Pointers vs std::function ---" << std::endl;
    std::cout << "Function pointer:" << std::endl;
    std::cout << "  • Faster (no overhead)" << std::endl;
    std::cout << "  • Only for free functions" << std::endl;
    std::cout << "\nstd::function:" << std::endl;
    std::cout << "  • Slower (type erasure overhead)" << std::endl;
    std::cout << "  • Can store lambdas, functors, member functions" << std::endl;

    return 0;
}

