phase3.solution:
#include <iostream>
#include <functional>
#include <vector>

int add(int a, int b) { return a + b; }
int subtract(int a, int b) { return a - b; }
int multiply(int a, int b) { return a * b; }

int main() {
    std::cout << "=== Function Pointers ===" << std::endl;
    int (*ops[])(int, int) = {add, subtract, multiply};
    std::string names[] = {"add", "subtract", "multiply"};

    for (int i = 0; i < 3; i++) {
        std::cout << names[i] << "(10,5) = " << ops[i](10, 5) << std::endl;
    }

    std::cout << "\n=== std::function with Lambda ===" << std::endl;
    std::function<int(int, int)> func = [](int a, int b) {
        return (a + b) * 2;
    };
    std::cout << "(3 + 4) * 2 = " << func(3, 4) << std::endl;

    std::cout << "\n=== std::function Vector ===" << std::endl;
    std::vector<std::function<int(int, int)>> funcs = {
        add,
        multiply,
        [](int a, int b) { return a / b; }
    };

    for (auto& f : funcs) {
        std::cout << f(20, 4) << std::endl;
    }

    return 0;
}
